// Main publications page logic
let allPublications = [];
let filteredPublications = [];
let currentFilter = 'all';
let currentSort = 'year-desc';
let searchQuery = '';

// Load publications and stats from JSON files (generated by fetch_scholar.py)
async function loadPublications() {
	try {
		const [pubResponse, statsResponse] = await Promise.all([
			fetch('publications_bib/publications.json'),
			fetch('publications_bib/scholar_stats.json')
		]);

		allPublications = await pubResponse.json();

		if (statsResponse.ok) {
			const stats = await statsResponse.json();
			updateStatsFromScholar(stats);
		} else {
			updateStatsFromData();
		}

		filterPublications();
		document.getElementById('loading').style.display = 'none';
	} catch (error) {
		console.error('Error loading publications:', error);
		document.getElementById('loading').innerHTML =
			'<p style="color: #e74c3c;">Error loading publications. Please try again later.</p>';
	}
}

// Update statistics from Google Scholar stats file
function updateStatsFromScholar(stats) {
	document.getElementById('total-pubs').textContent = stats.total_publications || allPublications.length;
	document.getElementById('total-citations').textContent = stats.total_citations || 0;
	document.getElementById('h-index').textContent = stats.h_index || 0;
	document.getElementById('i10-index').textContent = stats.i10_index || 0;

	const updatedEl = document.getElementById('last-updated');
	if (updatedEl && stats.last_updated) {
		updatedEl.textContent = `Last updated: ${stats.last_updated}`;
	}
}

// Fallback: compute stats from publication data
function updateStatsFromData() {
	document.getElementById('total-pubs').textContent = allPublications.length;
	const totalCitations = allPublications.reduce((sum, p) => sum + (p.citations || 0), 0);
	document.getElementById('total-citations').textContent = totalCitations;
	document.getElementById('h-index').textContent = '-';
	document.getElementById('i10-index').textContent = '-';
}

// Extract year from entry
function extractYear(entry) {
	if (entry.year) {
		const match = entry.year.match(/(\d{4})/);
		return match ? parseInt(match[1]) : null;
	}
	return null;
}

// Format author list
function formatAuthors(authors) {
	if (!authors) return '';
	const authorList = authors.split(/\s+and\s+/i);
	if (authorList.length <= 3) {
		return authorList.join(', ');
	}
	return authorList.slice(0, 3).join(', ') + ', et al.';
}

// Get human-readable type label
function getTypeLabel(type) {
	const labels = {
		'article': 'Journal Article',
		'inproceedings': 'Conference Paper',
		'incollection': 'Book Chapter',
		'book': 'Book',
		'mastersthesis': "Master's Thesis",
		'phdthesis': 'PhD Thesis',
		'techreport': 'Technical Report',
		'misc': 'Miscellaneous'
	};
	return labels[type] || type;
}

// Filter publications
function filterPublications() {
	filteredPublications = allPublications.filter(pub => {
		// Type filter
		let matchesType = false;
		if (currentFilter === 'all') {
			matchesType = true;
		} else if (currentFilter === 'highly-cited') {
			matchesType = (pub.citations || 0) >= 10;
		} else {
			matchesType = pub.type === currentFilter;
		}

		// Search filter
		const matchesSearch = searchQuery === '' ||
			(pub.title && pub.title.toLowerCase().includes(searchQuery)) ||
			(pub.author && pub.author.toLowerCase().includes(searchQuery)) ||
			(pub.journal && pub.journal.toLowerCase().includes(searchQuery)) ||
			(pub.booktitle && pub.booktitle.toLowerCase().includes(searchQuery));

		return matchesType && matchesSearch;
	});

	sortPublications();
	renderPublications();
}

// Sort publications
function sortPublications() {
	filteredPublications.sort((a, b) => {
		if (currentSort === 'year-desc') {
			return (extractYear(b) || 0) - (extractYear(a) || 0);
		} else if (currentSort === 'year-asc') {
			return (extractYear(a) || 0) - (extractYear(b) || 0);
		} else if (currentSort === 'citations-desc') {
			return (b.citations || 0) - (a.citations || 0);
		} else if (currentSort === 'citations-asc') {
			return (a.citations || 0) - (b.citations || 0);
		}
		return 0;
	});
}

// Render publications list
function renderPublications() {
	const container = document.getElementById('publications-list');
	const noResults = document.getElementById('no-results');

	if (filteredPublications.length === 0) {
		container.innerHTML = '';
		noResults.style.display = 'block';
		return;
	}

	noResults.style.display = 'none';

	let html = '';
	let lastYear = null;
	const showYearDividers = currentSort.startsWith('year');

	filteredPublications.forEach(pub => {
		const year = extractYear(pub);

		if (showYearDividers && year && year !== lastYear) {
			html += `<h3 style="margin-top: 2rem; margin-bottom: 1rem; color: #667eea; font-size: 1.5rem;">${year}</h3>`;
			lastYear = year;
		}

		html += renderPublication(pub);
	});

	container.innerHTML = html;
}

// Render a single publication
function renderPublication(pub) {
	const title = pub.title || 'Untitled';
	const authors = formatAuthors(pub.author);
	const year = extractYear(pub);
	const type = getTypeLabel(pub.type);
	const citations = pub.citations || 0;

	// Determine venue
	let venue = '';
	if (pub.journal) {
		venue = pub.journal;
		if (pub.volume) venue += `, Vol. ${pub.volume}`;
		if (pub.number) venue += ` (${pub.number})`;
		if (pub.pages) venue += `, pp. ${pub.pages}`;
	} else if (pub.booktitle) {
		venue = pub.booktitle;
	}

	// Title link
	let titleLink = pub.url || '';
	const titleHtml = titleLink
		? `<a href="${titleLink}" target="_blank" rel="noopener noreferrer">${title}</a>`
		: title;

	// Links
	let links = '';
	if (pub.eprint_url) {
		links += `<a href="${pub.eprint_url}" target="_blank" class="link-btn">
			<i class="fas fa-file-pdf"></i> PDF
		</a>`;
	}
	if (pub.url) {
		links += `<a href="${pub.url}" target="_blank" class="link-btn">
			<i class="fas fa-external-link-alt"></i> View
		</a>`;
	}

	// Badges
	let badges = '';
	if (year) {
		badges += `<span class="year-badge">${year}</span>`;
	}
	badges += `<span class="type-badge">${type}</span>`;
	if (citations > 0) {
		badges += `<span class="citations-badge"><i class="fas fa-quote-right"></i> ${citations}</span>`;
	}

	return `
		<div class="publication-entry">
			<div class="title">${titleHtml}</div>
			<div class="authors">${authors}</div>
			${venue ? `<div class="venue">${venue}</div>` : ''}
			<div class="meta">
				${badges}
			</div>
			${links ? `<div class="links">${links}</div>` : ''}
		</div>
	`;
}

// Event listeners
document.addEventListener('DOMContentLoaded', () => {
	loadPublications();

	// Filter buttons
	document.querySelectorAll('.filter-btn').forEach(btn => {
		btn.addEventListener('click', (e) => {
			const filter = e.target.dataset.filter;
			const sort = e.target.dataset.sort;

			if (filter) {
				document.querySelectorAll('[data-filter]').forEach(b => b.classList.remove('active'));
				e.target.classList.add('active');
				currentFilter = filter;
			} else if (sort) {
				document.querySelectorAll('[data-sort]').forEach(b => b.classList.remove('active'));
				e.target.classList.add('active');
				currentSort = sort;
			}

			filterPublications();
		});
	});

	// Search input
	const searchInput = document.getElementById('search-input');
	searchInput.addEventListener('input', (e) => {
		searchQuery = e.target.value.toLowerCase();
		filterPublications();
	});
});
